/* ──────────────────────────────────────────────
   BTCalendar — organism stylesheet
   Shared with React. No hex fallbacks anywhere.
   ────────────────────────────────────────────── */

/* Container */
.bt-calendar {
  display: inline-flex;
  flex-direction: column;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
  user-select: none;
  box-shadow: 0px 10px 7.5px rgba(0, 0, 0, 0.10), 0px 4px 3px rgba(0, 0, 0, 0.05);
}

/* With presets: row layout */
.bt-calendar--has-presets {
  flex-direction: row;
}

.bt-calendar__preset-panel {
  width: 160px;
  border-inline-end: 1px solid var(--border-primary);
  padding: var(--space-sm) 0;
  flex-shrink: 0;
}

/* Body (right side of preset panel, or full width without presets) */
.bt-calendar__body {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  padding: var(--space-lg);
  gap: var(--space-lg);
}

/* Dual month (range) — side-by-side months */
.bt-calendar__months {
  display: flex;
  flex-direction: row;
  gap: var(--space-lg);
}

.bt-calendar__month {
  padding: 0;
}

.bt-calendar__month-subtitle {
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-secondary);
  padding: var(--space-xs);
  line-height: var(--typography-line-height-xs);
  margin-bottom: var(--space-xs);
}

/* ── Header ─────────────────────────────────── */
.bt-calendar__header {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  margin-bottom: var(--space-sm);
}

/* Nav prev/next buttons */
.bt-calendar__nav-btn {
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  border: none;
  background: none;
  cursor: pointer;
  color: var(--color-brand-primary);
  border-radius: var(--radius-xs);
  flex-shrink: 0;
  transition: background 0.1s;
}

.bt-calendar__nav-btn:hover:not(:disabled) {
  background: var(--bg-subtle);
}

.bt-calendar__nav-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* RTL: mirror the chevron glyphs so the left button still shows "<" and the
 * right still shows ">", while prev/next semantics follow logical direction. */
[dir="rtl"] .bt-calendar__nav-btn svg {
  transform: scaleX(-1);
}

.bt-calendar__header-labels {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  flex: 1;
}

/* Pill wrapper — needed for dropdown anchor reference */
.bt-calendar__pill-wrapper {
  position: relative;
}

/* Month / year pill buttons */
.bt-calendar__header-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  width: 106px;
  padding: var(--space-xs) var(--space-sm);
  border: none;
  background: none;
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--color-brand-primary);
  font-family: var(--typography-font-family-sans);
  border-radius: var(--radius-xs);
  white-space: nowrap;
}

.bt-calendar__header-pill:hover {
  background: var(--bg-subtle);
}

.bt-calendar__header-arrow {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  transition: transform 0.15s ease;
}

.bt-calendar__header-arrow--open {
  transform: rotate(180deg);
}

/* ── Weekday row ─────────────────────────────── */
.bt-calendar__weekdays {
  display: grid;
  grid-template-columns: repeat(7, 40px);
  margin-bottom: var(--space-xs);
}

.bt-calendar__weekday {
  text-align: center;
  font-size: var(--typography-font-size-xs);
  color: var(--text-secondary);
  padding: var(--space-xs) 0;
  width: 40px;
}

/* ── Day grid ────────────────────────────────── */
.bt-calendar__days {
  display: grid;
  grid-template-columns: repeat(7, 40px);
  gap: 0;
  row-gap: var(--space-sm);
}

/* ── Day cell ────────────────────────────────── */
.bt-calendar__day {
  position: relative;
  width: 40px;
  height: 40px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  transition: background 0.1s;
  font-family: var(--typography-font-family-sans);
  padding: 0;
}

.bt-calendar__day:hover:not(.bt-calendar__day--disabled):not(.bt-calendar__day--selected):not(.bt-calendar__day--range-start):not(.bt-calendar__day--range-end):not(.bt-calendar__day--range-start-only):not(.bt-calendar__day--range-start-hover):not(.bt-calendar__day--range-end-hover):not(.bt-calendar__day--in-range):not(.bt-calendar__day--in-range-hover) {
  background: var(--bg-subtle);
}

/* ── Day states ──────────────────────────────── */
.bt-calendar__day--outside {
  color: var(--text-tertiary);
}

.bt-calendar__day--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
}

.bt-calendar__day--today {
  outline: 1.5px solid var(--color-brand-primary);
  outline-offset: -1.5px;
  border-radius: var(--radius-md);
}

.bt-calendar__day--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md);
}

.bt-calendar__day--selected:hover {
  background: var(--color-brand-primary-bold);
}

.bt-calendar__day--range-start {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md) 0 0 var(--radius-md);
}

.bt-calendar__day--range-end {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}

.bt-calendar__day--in-range {
  background: var(--color-brand-primary-subtle);
  color: var(--text-primary);
  border-radius: 0;
}

/* When start and end are the same day */
.bt-calendar__day--range-start.bt-calendar__day--range-end {
  border-radius: var(--radius-md);
}

/* Start selected but no end yet — fully rounded like a single selected day */
.bt-calendar__day--range-start-only {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
  border-radius: var(--radius-md);
}

/* Hover preview endpoints — brand primary at reduced opacity (pre-selected state) */
.bt-calendar__day--range-start-hover {
  background: color-mix(in srgb, var(--color-brand-primary-bold) 55%, transparent);
  color: var(--text-inverse);
  border-radius: var(--radius-md) 0 0 var(--radius-md);
}

.bt-calendar__day--range-end-hover {
  background: color-mix(in srgb, var(--color-brand-primary-bold) 55%, transparent);
  color: var(--text-inverse);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
}

/* Hover preview fill — lighter than confirmed in-range */
.bt-calendar__day--in-range-hover {
  background: var(--bg-subtle);
  color: var(--text-primary);
  border-radius: 0;
}

/* ── Event dot ───────────────────────────────── */
.bt-calendar__day-dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: var(--color-brand-secondary);
  margin-top: 2px;
  display: block;
  flex-shrink: 0;
}

/* ── Month view (3×4 grid) ───────────────────── */
.bt-calendar__month-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-xs);
  padding: 0 var(--space-sm) var(--space-sm);
}

.bt-calendar__month-item {
  padding: var(--space-sm);
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  text-align: center;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__month-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__month-item--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

.bt-calendar__month-item--current {
  outline: 1.5px solid var(--color-brand-primary);
  outline-offset: -1.5px;
}

/* ── Year view ───────────────────────────────── */
.bt-calendar__year-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  max-height: 224px;
  overflow-y: auto;
  padding: 0 var(--space-sm) var(--space-sm);
}

.bt-calendar__year-item {
  padding: var(--space-sm) var(--space-lg);
  border: none;
  background: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-primary);
  text-align: start;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__year-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__year-item--selected {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

/* ── Preset panel items ──────────────────────── */
.bt-calendar__preset-item {
  width: 100%;
  padding: var(--space-sm) var(--space-lg);
  border: none;
  background: none;
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  color: var(--text-secondary);
  text-align: start;
  font-family: var(--typography-font-family-sans);
  transition: background 0.1s;
}

.bt-calendar__preset-item:hover {
  background: var(--bg-subtle);
}

.bt-calendar__preset-item--active {
  color: var(--color-brand-primary-bold);
  background: var(--bg-subtle);
  font-weight: var(--typography-font-weight-semibold);
}

/* ── Preset chips (wrap row below the day grid) ─ */
.bt-calendar__preset-chips {
  contain: inline-size;           /* prevent chips from expanding calendar width */
  margin: 0 -16px;                /* break out of bt-calendar__body 16px padding */
  padding: var(--space-lg) var(--space-sm);
  background: var(--bg-secondary);
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  justify-content: center;
}


/* ── Footer (date display + action buttons) ──── */
.bt-calendar__footer {
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.bt-calendar__footer--range {
  flex-direction: row;
  gap: var(--space-sm);
  align-items: center;
}

.bt-calendar__date-display {
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--color-brand-primary);
  font-family: var(--typography-font-family-sans);
  min-height: 20px;
}

.bt-calendar__footer--range .bt-calendar__date-display {
  flex: 1;
  text-align: start;
}

.bt-calendar__footer-actions {
  display: flex;
  gap: var(--space-sm);
}

.bt-calendar__footer-actions > * {
  flex: 1;
}

.bt-calendar__footer--range .bt-calendar__footer-actions > * {
  flex: none;
}

export type BTCalendarMode = 'single' | 'range';

export interface BTCalendarPreset {
  label: string;
  getValue: () => [Date, Date?];
}

export interface BTCalendarProps {
  mode?: BTCalendarMode;            // default: 'single'
  modelValue?: Date | null;         // single-mode v-model
  rangeValue?: [Date, Date] | null; // range-mode v-model:rangeValue
  presets?: BTCalendarPreset[];     // sidebar presets (omit = no panel)
  minDate?: Date;
  maxDate?: Date;
  disabledDates?: (date: Date) => boolean;
  eventDates?: Date[];
  initialMonth?: Date;
  locale?: string;                  // default: 'id-ID'
  showFooter?: boolean;             // default: true; shows Apply+Cancel
  showPreset?: boolean;             // default: false; shows built-in date preset chips below the grid
}

export interface CalendarDay {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  isRangeStart: boolean;
  isRangeEnd: boolean;
  isRangeStartOnly: boolean;
  isInRange: boolean;
  isHoverPreviewPoint: boolean;
  isInRangeHover: boolean;
  isDisabled: boolean;
  hasEvent: boolean;
}

export function isSameDay(a: Date, b: Date): boolean {
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}

export function isInRange(date: Date, start: Date, end: Date): boolean {
  const d = date.getTime();
  const s = start.getTime();
  const e = end.getTime();
  const lo = Math.min(s, e);
  const hi = Math.max(s, e);
  return d > lo && d < hi;
}

export function isToday(date: Date): boolean {
  return isSameDay(date, new Date());
}

export function startOfMonth(date: Date): Date {
  return new Date(date.getFullYear(), date.getMonth(), 1);
}

export function endOfMonth(date: Date): Date {
  return new Date(date.getFullYear(), date.getMonth() + 1, 0);
}

export function addMonths(date: Date, n: number): Date {
  const d = new Date(date);
  d.setDate(1); // avoid day-overflow when changing month
  d.setMonth(d.getMonth() + n);
  return d;
}

export function getDaysInMonth(year: number, month: number): number {
  return new Date(year, month + 1, 0).getDate();
}

export function clampDate(date: Date, min?: Date, max?: Date): Date {
  let d = date;
  if (min && d < min) d = min;
  if (max && d > max) d = max;
  return d;
}

type CalendarLang = 'id' | 'en' | 'ar' | 'he';

export function calendarLang(locale: string): CalendarLang {
  if (locale.startsWith('ar')) return 'ar';
  if (locale.startsWith('he') || locale.startsWith('iw')) return 'he';
  if (locale.startsWith('id')) return 'id';
  return 'en';
}

const CAL_STRINGS = {
  id: {
    cancel: 'Batal', apply: 'Terapkan',
    yesterday: 'Kemarin', today: 'Hari ini', tomorrow: 'Besok',
    thisWeek: 'Minggu ini', lastWeek: 'Minggu lalu',
    thisMonth: 'Bulan ini', lastMonth: 'Bulan lalu',
    calendar: 'Kalender', pickMonth: 'Pilih bulan', pickYear: 'Pilih tahun',
  },
  en: {
    cancel: 'Cancel', apply: 'Apply',
    yesterday: 'Yesterday', today: 'Today', tomorrow: 'Tomorrow',
    thisWeek: 'This week', lastWeek: 'Last week',
    thisMonth: 'This month', lastMonth: 'Last month',
    calendar: 'Calendar', pickMonth: 'Select month', pickYear: 'Select year',
  },
  ar: {
    cancel: 'إلغاء', apply: 'تطبيق',
    yesterday: 'أمس', today: 'اليوم', tomorrow: 'غدًا',
    thisWeek: 'هذا الأسبوع', lastWeek: 'الأسبوع الماضي',
    thisMonth: 'هذا الشهر', lastMonth: 'الشهر الماضي',
    calendar: 'التقويم', pickMonth: 'اختر الشهر', pickYear: 'اختر السنة',
  },
  he: {
    cancel: 'ביטול', apply: 'החל',
    yesterday: 'אתמול', today: 'היום', tomorrow: 'מחר',
    thisWeek: 'השבוע', lastWeek: 'השבוע שעבר',
    thisMonth: 'החודש', lastMonth: 'החודש שעבר',
    calendar: 'לוח שנה', pickMonth: 'בחר חודש', pickYear: 'בחר שנה',
  },
} as const;

export function calendarStrings(locale: string) {
  return CAL_STRINGS[calendarLang(locale)];
}

export function getWeekdayNames(locale: string): string[] {
  const names: string[] = [];
  // Start from Sunday (0) — create 7 days starting from a known Sunday (2021-01-03)
  for (let i = 0; i < 7; i++) {
    const date = new Date(2021, 0, 3 + i); // Jan 3, 2021 is Sunday
    names.push(
      date.toLocaleDateString(locale, { weekday: 'short' }).replace('.', ''),
    );
  }
  return names;
}

export function getMonthName(date: Date, locale: string): string {
  return date.toLocaleDateString(locale, { month: 'long', year: 'numeric' });
}

export function getMonthShortName(date: Date, locale: string): string {
  return date.toLocaleDateString(locale, { month: 'short' });
}

/** Returns the short month name for a 1-based month number (1 = January). */
function getMonthShortNameByNumber(month: number, locale: string): string {
  const date = new Date(2000, month - 1, 1);
  return date.toLocaleDateString(locale, { month: 'short' }).replace('.', '');
}

/** Formats a date as "DD MMM YYYY" (e.g. "11 Jan 2026"). Returns empty string if null. */
export function formatDate(date: Date | null | undefined, locale: string): string {
  if (!date) return '';
  const day = date.getDate().toString().padStart(2, '0');
  const month = getMonthShortNameByNumber(date.getMonth() + 1, locale);
  const year = date.getFullYear();
  return `${day} ${month} ${year}`;
}

/** Formats a date range as "DD MMM YYYY - DD MMM YYYY". Shows only start if end is null. */
export function formatDateRange(
  start: Date | null | undefined,
  end: Date | null | undefined,
  locale: string
): string {
  if (!start) return '';
  if (!end) return formatDate(start, locale);
  return `${formatDate(start, locale)} - ${formatDate(end, locale)}`;
}

function isDateDisabled(
  date: Date,
  options: {
    disabledDates?: (d: Date) => boolean;
    minDate?: Date;
    maxDate?: Date;
  },
): boolean {
  if (options.minDate) {
    const minStart = new Date(
      options.minDate.getFullYear(),
      options.minDate.getMonth(),
      options.minDate.getDate(),
    );
    const dateStart = new Date(date.getFullYear(), date.getMonth(), date.getDate());
    if (dateStart < minStart) return true;
  }
  if (options.maxDate) {
    const maxStart = new Date(
      options.maxDate.getFullYear(),
      options.maxDate.getMonth(),
      options.maxDate.getDate(),
    );
    const dateStart = new Date(date.getFullYear(), date.getMonth(), date.getDate());
    if (dateStart > maxStart) return true;
  }
  if (options.disabledDates && options.disabledDates(date)) return true;
  return false;
}

export function generateCalendarDays(
  year: number,
  month: number, // 0-indexed
  options: {
    selectedDate?: Date | null;
    rangeStart?: Date | null;
    rangeEnd?: Date | null;
    rangeHover?: Date | null;
    disabledDates?: (d: Date) => boolean;
    eventDates?: Date[];
    minDate?: Date;
    maxDate?: Date;
  } = {},
): CalendarDay[] {
  const days: CalendarDay[] = [];

  const firstDay = new Date(year, month, 1);
  const startDow = firstDay.getDay(); // 0 = Sunday

  // Fill from previous month
  for (let i = startDow - 1; i >= 0; i--) {
    const date = new Date(year, month, -i);
    days.push(buildDay(date, false, options));
  }

  // Current month days
  const daysInMonth = getDaysInMonth(year, month);
  for (let d = 1; d <= daysInMonth; d++) {
    const date = new Date(year, month, d);
    days.push(buildDay(date, true, options));
  }

  // Fill to complete 42 cells (6 rows × 7 cols)
  const remaining = 42 - days.length;
  for (let d = 1; d <= remaining; d++) {
    const date = new Date(year, month + 1, d);
    days.push(buildDay(date, false, options));
  }

  return days;
}

function buildDay(
  date: Date,
  isCurrentMonth: boolean,
  options: {
    selectedDate?: Date | null;
    rangeStart?: Date | null;
    rangeEnd?: Date | null;
    rangeHover?: Date | null;
    disabledDates?: (d: Date) => boolean;
    eventDates?: Date[];
    minDate?: Date;
    maxDate?: Date;
  },
): CalendarDay {
  const { selectedDate, rangeStart, rangeEnd, rangeHover, eventDates } = options;

  const selected = !!(selectedDate && isSameDay(date, selectedDate));

  let rangeStartDay = false;
  let rangeEndDay = false;
  let rangeStartOnly = false;
  let inRange = false;
  let isHoverPreviewPoint = false;
  let isInRangeHover = false;

  if (rangeStart) {
    const hasHoverPreview = !rangeEnd && rangeHover && !isSameDay(rangeHover, rangeStart);
    const effectiveEnd = rangeEnd ?? (hasHoverPreview ? rangeHover! : null);

    if (effectiveEnd) {
      const lo = rangeStart <= effectiveEnd ? rangeStart : effectiveEnd;
      const hi = rangeStart <= effectiveEnd ? effectiveEnd : rangeStart;
      rangeStartDay = isSameDay(date, lo);
      rangeEndDay = isSameDay(date, hi);
      const inRangeBetween = isInRange(date, lo, hi);

      if (hasHoverPreview) {
        // Hover preview — separate from confirmed
        isHoverPreviewPoint = isSameDay(date, rangeHover!);
        isInRangeHover = inRangeBetween;
      } else {
        // Confirmed range (both endpoints selected)
        inRange = inRangeBetween;
      }
    } else {
      // Only start selected, no active range
      rangeStartDay = isSameDay(date, rangeStart);
      rangeStartOnly = rangeStartDay;
    }
  }

  const hasEvent = !!(
    eventDates && eventDates.some((ed) => isSameDay(ed, date))
  );

  const disabled = isDateDisabled(date, options);

  return {
    date,
    isCurrentMonth,
    isToday: isToday(date),
    isSelected: selected,
    isRangeStart: rangeStartDay,
    isRangeEnd: rangeEndDay,
    isRangeStartOnly: rangeStartOnly,
    isInRange: inRange,
    isHoverPreviewPoint,
    isInRangeHover,
    isDisabled: disabled,
    hasEvent,
  };
}

/**
 * positionFloating — shared smart-flip positioning utility.
 *
 * Measures available space around a trigger element and places a floating
 * panel (already rendered in the DOM at position:fixed) below or above
 * depending on which direction has more room. Clamps horizontally so the
 * panel never overflows the viewport edges.
 *
 * Usage:
 *   // After the panel is in the DOM (watch flush:'post' or nextTick):
 *   positionBelow(triggerEl, panelEl, { gap: 4, margin: 8 });
 *
 * Also exported: positionDropdown — same algorithm but centres the panel
 * horizontally over an anchor element (for header pill dropdowns).
 */

export interface PositionOptions {
  /** Gap between trigger edge and panel edge. Default: 4. */
  gap?: number;
  /** Minimum distance from viewport edges. Default: 8. */
  margin?: number;
}

/**
 * Position a panel below or above `trigger`, left-aligned (then clamped).
 * Mutates `panel.style.top / left` and returns the resolved direction.
 */
export function positionBelow(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: PositionOptions = {},
): 'below' | 'above' {
  const { gap = 4, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Vertical: prefer below, flip above when there's not enough space ────────
  const spaceBelow = vh - tRect.bottom - gap;
  const spaceAbove = tRect.top - gap;
  const goAbove    = spaceBelow < pRect.height && spaceAbove >= pRect.height;

  const top = goAbove
    ? tRect.top  - pRect.height - gap
    : tRect.bottom + gap;

  // ── Horizontal: align to trigger start edge, clamp to viewport ─────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  let left = isRtl ? tRect.right - pRect.width : tRect.left;
  if (left + pRect.width > vw - margin) left = vw - margin - pRect.width;
  if (left < margin)                    left = margin;

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;

  return goAbove ? 'above' : 'below';
}

export type PopoverSide   = 'top' | 'bottom' | 'left' | 'right';
export type PopoverAlign  = 'start' | 'center' | 'end';

/**
 * Position a popover panel relative to a trigger with auto-flip on all axes.
 * Respects the requested `side` but flips to the opposite if there is no room.
 */
export function positionPopover(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: { side?: PopoverSide; align?: PopoverAlign; sideOffset?: number; margin?: number } = {},
): void {
  const { side = 'bottom', align = 'start', sideOffset = 8, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Resolve side with auto-flip ─────────────────────────────────────────────
  let resolvedSide = side;
  if (side === 'bottom') {
    const fits = vh - tRect.bottom - sideOffset >= pRect.height;
    if (!fits && tRect.top - sideOffset >= pRect.height) resolvedSide = 'top';
  } else if (side === 'top') {
    const fits = tRect.top - sideOffset >= pRect.height;
    if (!fits && vh - tRect.bottom - sideOffset >= pRect.height) resolvedSide = 'bottom';
  } else if (side === 'right') {
    const fits = vw - tRect.right - sideOffset >= pRect.width;
    if (!fits && tRect.left - sideOffset >= pRect.width) resolvedSide = 'left';
  } else /* left */ {
    const fits = tRect.left - sideOffset >= pRect.width;
    if (!fits && vw - tRect.right - sideOffset >= pRect.width) resolvedSide = 'right';
  }

  // ── Main axis ───────────────────────────────────────────────────────────────
  let top  = 0;
  let left = 0;
  if      (resolvedSide === 'bottom') top  = tRect.bottom + sideOffset;
  else if (resolvedSide === 'top')    top  = tRect.top - pRect.height - sideOffset;
  else if (resolvedSide === 'right')  left = tRect.right  + sideOffset;
  else /* left */                     left = tRect.left  - pRect.width - sideOffset;

  // ── Cross axis (alignment) — flip start/end in RTL ──────────────────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  const resolvedAlign = isRtl
    ? (align === 'start' ? 'end' : align === 'end' ? 'start' : align)
    : align;

  if (resolvedSide === 'top' || resolvedSide === 'bottom') {
    if      (resolvedAlign === 'start')  left = tRect.left;
    else if (resolvedAlign === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
    else /* end */                       left = tRect.right - pRect.width;

    // Clamp horizontally
    left = Math.min(left, vw - margin - pRect.width);
    left = Math.max(left, margin);
  } else {
    if      (align === 'start')  top = tRect.top;
    else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
    else /* end */               top = tRect.bottom - pRect.height;

    // Clamp vertically
    top = Math.min(top, vh - margin - pRect.height);
    top = Math.max(top, margin);
  }

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
}

/**
 * Position a small dropdown centred horizontally over `anchor`, below or above.
 * Used by BTCalendarHeader month/year pills.
 */
export function positionCentered(
  anchor: HTMLElement,
  dropdown: HTMLElement,
  opts: PositionOptions = {},
): void {
  const { gap = 4, margin = 8 } = opts;
  const aRect = anchor.getBoundingClientRect();
  const dRect = dropdown.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // Vertical: prefer below, flip above
  const spaceBelow = vh - aRect.bottom - gap;
  const spaceAbove = aRect.top - gap;
  const goAbove    = spaceBelow < dRect.height && spaceAbove >= dRect.height;

  const top = goAbove
    ? aRect.top  - dRect.height - gap
    : aRect.bottom + gap;

  // Horizontal: centre over anchor, clamp
  let left = aRect.left + aRect.width / 2 - dRect.width / 2;
  if (left + dRect.width > vw - margin) left = vw - margin - dRect.width;
  if (left < margin)                    left = margin;

  dropdown.style.top  = `${Math.round(top)}px`;
  dropdown.style.left = `${Math.round(left)}px`;
}
